metadata.initialCode:
import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const result = await callMcpSkill({
    toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
    toolName: "compare_event_outcome_quotes",
    args: {
      eventQuery: "2026 FIFA World Cup winner",
      outcomes: ["Spain", "Brazil", "France"]
    }
  });

  const matchedOutcomes = Array.isArray(result?.matchedOutcomes) ? result.matchedOutcomes : [];
  const rows = matchedOutcomes.map((o) => ({
    matchedName: o.matchedName,
    tokenId: o.tokenId,
    currentPrice: o.currentPrice,
    spread: o.spread,
    spreadPercent: o.spreadPercent,
    bestBid: o.bestBid,
    bestAsk: o.bestAsk,
    volume: o.volume,
    impliedProbability: o.impliedProbability
  }));

  const widest = result?.widestSpreadOutcome || null;

  return {
    eventTitle: result?.eventTitle,
    eventUrl: result?.eventUrl,
    eventSlug: result?.eventSlug,
    matchedOutcomes: rows,
    unmatchedOutcomes: Array.isArray(result?.unmatchedOutcomes) ? result.unmatchedOutcomes : [],
    widestSpreadOutcome: widest
  };
}

