import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";


function __normalizeToolArrayOutput(value) {
  if (Array.isArray(value)) {
    return value;
  }
  if (!value || typeof value !== "object") {
    return [];
  }

  const directCandidates = [
    value.results,
    value.items,
    value.rows,
    value.markets,
    value.events,
    value.entries,
    value.records,
    value.candidates,
    value.data,
  ];

  for (const candidate of directCandidates) {
    if (Array.isArray(candidate)) {
      return candidate;
    }
  }

  const nestedData =
    value.data && typeof value.data === "object" ? value.data : null;
  if (!nestedData) {
    return [];
  }

  const nestedCandidates = [
    nestedData.results,
    nestedData.items,
    nestedData.rows,
    nestedData.markets,
    nestedData.events,
    nestedData.entries,
    nestedData.records,
    nestedData.candidates,
